public class TypeConversionDemo {
    public static void main(String[] args) {
        // Widening (Implicit)
        int intVal = 100;
        long longVal = intVal;
        double doubleVal = longVal;
        System.out.println("Widening: int(" + intVal + ") → long(" + longVal + ") → double(" + doubleVal + ")");

        // Narrowing (Explicit)
        double d = 123.456;
        int i = (int) d;
        byte b = (byte) d;
        System.out.println("Narrowing: double(" + d + ") → int(" + i + ") → byte(" + b + ")");
    }
}

