import java.util.Scanner;
public class GradeDemo {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        System.out.print("Enter marks: ");
        int marks = sc.nextInt();

        // if-else-if
        char grade;
        if (marks >= 90) grade = 'A';
        else if (marks >= 75) grade = 'B';
        else if (marks >= 60) grade = 'C';
        else if (marks >= 40) grade = 'D';
        else grade = 'F';
        System.out.println("Grade: " + grade);

        // switch (based on grade)
        switch (grade) {
            case 'A': System.out.println("Excellent!"); break;
            case 'B': System.out.println("Good!"); break;
            case 'C': System.out.println("Average!"); break;
            case 'D': System.out.println("Below Average!"); break;
            case 'F': System.out.println("Failed!"); break;
        }
        sc.close();
    }
}

public class LoopsDemo {
    public static void main(String[] args) {
        System.out.print("for: ");
        for (int i = 1; i <= 5; i++) System.out.print(i + " ");

        System.out.print("\nwhile: ");
        int j = 1;
        while (j <= 5) { System.out.print(j + " "); j++; }

        System.out.print("\ndo-while: ");
        int k = 1;
        do { System.out.print(k + " "); k++; } while (k <= 5);

        System.out.print("\nenhanced for: ");
        int[] arr = {1, 2, 3, 4, 5};
        for (int num : arr) System.out.print(num + " ");
    }
}

public class JumpDemo {
    public static void main(String[] args) {
        // break
        for (int i = 1; i <= 5; i++) {
            if (i == 3) break;
            System.out.print(i + " ");
        }
        System.out.println("(break at 3)");

        // continue
        for (int i = 1; i <= 5; i++) {
            if (i == 3) continue;
            System.out.print(i + " ");
        }
        System.out.println("(skipped 3)");

        // return
        System.out.println("Before return");
        return; // exits method
        // System.out.println("After return"); // unreachable
    }
}

import java.math.*;
public class BigNumbers {
    public static void main(String[] args) {
        BigInteger bi = new BigInteger("12345678901234567890");
        System.out.println("BigInteger: " + bi.multiply(new BigInteger("2")));

        BigDecimal bd = new BigDecimal("0.1").add(new BigDecimal("0.2"));
        System.out.println("BigDecimal (exact): " + bd);
        // vs double: 0.1 + 0.2 = 0.30000000000000004
    }
}

public class ArrayDemo {
    public static void main(String[] args) {
        // 1D Array
        int[] arr = {10, 20, 30, 40, 50};
        System.out.println("1D Array:");
        for (int i = 0; i < arr.length; i++) {
            System.out.print(arr[i] + " ");
        }

        // 2D Array
        int[][] matrix = {{1,2,3}, {4,5,6}, {7,8,9}};
        System.out.println("\n\n2D Array (Matrix):");
        for (int i = 0; i < matrix.length; i++) {
            for (int j = 0; j < matrix[i].length; j++) {
                System.out.print(matrix[i][j] + " ");
            }
            System.out.println();
        }
    }
}

public class PassArrayDemo {
    public static void main(String[] args) {
        int[] numbers = {1, 2, 3, 4, 5};
        System.out.print("Original: ");
        printArray(numbers);

        modifyArray(numbers);
        System.out.print("After modify: ");
        printArray(numbers);

        int[] squared = squareArray(numbers);
        System.out.print("Squared: ");
        printArray(squared);
        System.out.print("Original unchanged: ");
        printArray(numbers);
    }

    public static void printArray(int[] arr) {
        for (int num : arr) System.out.print(num + " ");
        System.out.println();
    }

    public static void modifyArray(int[] arr) {
        for (int i = 0; i < arr.length; i++) {
            arr[i] = arr[i] * 2;
        }
    }

    public static int[] squareArray(int[] arr) {
        int[] result = new int[arr.length];
        for (int i = 0; i < arr.length; i++) {
            result[i] = arr[i] * arr[i];
        }
        return result;
    }
}
